const BRANDS = ["Acer","Addison","Almera","Bencup","Bic","Bion","Brons","Brother","Canon","Casio","Dark","Delta","Dilman","Duracell","Edding","Epson","Esselte","Ethex","Everest","Faber-Castell","Flood","HP","Havit","KLAS","KRAF","Kyocera","Lenova","Liz","Mas","Noki","Oyal","Pensan","Pereja","Philips","Picador","Pritt","Rapid","Rotring","S-Link","Samsung","Serve","Silka","SvetoCopy","TEKNO","Tanex","Tipex","Trust","Umix","UniNote","Utax","Vege"];

const BRAND_LOGOS = [
  { name:'Faber-Castell', img:'img/faber castel.png'         },
  { name:'Canon',         img:'img/brands/canon.svg'         },
  { name:'Epson',         img:'img/brands/epson.svg',  scale:1.3 },
  { name:'Bic',           img:'img/bic.png'                  },
  { name:'Kyocera',       img:'img/brands/kyocera.svg'       },
  { name:'KRAF',          img:'img/kraf.jpg',          scale:1.3 },
  { name:'Mas',           img:'img/mas.png',           scale:1.3 },
  { name:'HP',            img:'img/brands/hp.svg',     scale:1.3 },
  { name:'Esselte',       img:'img/esselte.png'              },
  { name:'Edding',        img:'img/brands/edding.svg'        },
  { name:'Duracell',      img:'img/duracel.jpg'              },
  { name:'Pereja',        img:'img/pereja_logo.jpg',   scale:1.3 },
];

/* ── STATE ── */
let cart = [], fCat = '', fBrand = '', modalProd = null, slideIdx = 0, currentPage = 1, searchQuery = '';

/* ── HELPERS ── */
function pImg(url, w=320, h=320) {
  if (!url) return '';
  return `https://images.weserv.nl/?url=${encodeURIComponent(url)}&w=${w}&h=${h}&fit=contain&output=webp&q=85`;
}

function imgTag(url, name) {
  const src = pImg(url);
  if (!src) return `<div class="pcard-ph"><svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1"><rect x="3" y="3" width="18" height="18" rx="2"/></svg></div>`;
  return `<img src="${src}" data-o="${url}" alt="${(name||'').replace(/"/g,"'")}" loading="lazy" style="opacity:0;transition:opacity .35s" onload="this.style.opacity=1" onerror="this.onerror=null;var o=this.dataset.o;if(o&&this.src!==o){this.src=o;}else{this.style.display='none';this.parentNode.innerHTML='<div class=\'pcard-ph\'><svg fill=\'none\' viewBox=\'0 0 24 24\' stroke=\'currentColor\' stroke-width=\'1\'><rect x=\'3\' y=\'3\' width=\'18\' height=\'18\' rx=\'2\'/></svg></div>';}">`;
}

function fmt(n) {
  if(!n) return '0,00 ₺';
  return parseFloat(n).toLocaleString('tr-TR',{minimumFractionDigits:2})+' ₺';
}

/* ── PRODUCT CARD ── */
function pCard(p, idx) {
  const disc = p.strikePrice && parseFloat(p.strikePrice) > parseFloat(p.price||0);
  const badge = p.ribbon === 'En Çok Satan'
    ? '<div class="pcard-badge best">⭐ En Çok Satan</div>'
    : disc ? '<div class="pcard-badge sale">İndirim</div>' : '';
  return `<article class="pcard" onclick="openModal(${idx})" itemscope itemtype="https://schema.org/Product">${badge}
    <div class="pcard-img">${imgTag(p.img, p.name)}</div>
    <div class="pcard-body">
      ${p.brand?`<div class="pcard-brand" itemprop="brand">${p.brand}</div>`:''}
      <div class="pcard-name" itemprop="name">${p.name}</div>
      <div class="pcard-foot">
        <div class="pcard-prices" itemprop="offers" itemscope itemtype="https://schema.org/Offer">
          ${disc?`<div class="pcard-old">${fmt(p.strikePrice)}</div>`:''}
          <div class="pcard-price${disc?' disc':''}" itemprop="price" content="${p.price}">${fmt(p.price)}</div>
          <meta itemprop="priceCurrency" content="TRY">
        </div>
        <button class="pcard-add" aria-label="${p.name} sepete ekle" onclick="event.stopPropagation();addCart(${idx},this)">
          <svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5"><path d="M12 4v16m8-8H4"/></svg>
        </button>
      </div>
    </div></article>`;
}

/* ── RENDER HOME ── */
function renderHome() {
  document.getElementById('brandsRow').innerHTML = BRAND_LOGOS.map(b=>`<button class="brand-logo-card" onclick="fCat='';fBrand='${b.name}';showAll(null)" aria-label="${b.name}"><img src="${b.img}" alt="${b.name}" class="brand-logo-img" loading="lazy"${b.scale?` style="transform:scale(${b.scale})"`:''}></button>`).join('');
  const bests = PRODUCTS.filter(p=>p.ribbon==='En Çok Satan').slice(0,12);
  document.getElementById('bestRow').innerHTML = bests.map(p=>pCard(p,PRODUCTS.indexOf(p))).join('');
  [['tonerRow','Toner & Kartuş'],['printerRow','Yazıcı & Fotokopi'],['kalemRow','Ofis ve Kırtasiye'],['dosyaRow','Ambalaj Malzemeleri'],['elektronikRow','Elektronik']].forEach(([id,cat])=>{
    const el = document.getElementById(id);
    if(el) el.innerHTML = PRODUCTS.filter(p=>p.category===cat).slice(0,12).map(p=>pCard(p,PRODUCTS.indexOf(p))).join('');
  });
}

/* ── FILTER & SORT ── */
function getFiltered() {
  let l=[...PRODUCTS];
  if(fCat) l=l.filter(p=>p.category===fCat);
  if(fBrand) l=l.filter(p=>p.brand===fBrand);
  const s=document.getElementById('sortSel').value;
  if(s==='pa') l.sort((a,b)=>(a.price||0)-(b.price||0));
  else if(s==='pd') l.sort((a,b)=>(b.price||0)-(a.price||0));
  else if(s==='na') l.sort((a,b)=>a.name.localeCompare(b.name,'tr'));
  else if(s==='nd') l.sort((a,b)=>b.name.localeCompare(a.name,'tr'));
  return l;
}

const PER_PAGE = 24;

function renderAll() {
  let l = getFiltered();
  if (searchQuery) {
    const lq = searchQuery.toLowerCase();
    l = l.filter(p =>
      p.name.toLowerCase().includes(lq) ||
      (p.brand||'').toLowerCase().includes(lq) ||
      (p.sku||'').toLowerCase().includes(lq)
    );
  }
  const total = l.length;
  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
  if (currentPage > totalPages) currentPage = 1;
  const start = (currentPage - 1) * PER_PAGE;
  const pageItems = l.slice(start, start + PER_PAGE);
  document.getElementById('allInfo').textContent = searchQuery
    ? total + ' sonuç: "' + searchQuery + '"'
    : total + ' ürün listelendi';
  document.getElementById('allGrid').innerHTML = pageItems.map(p => pCard(p, PRODUCTS.indexOf(p))).join('');
  renderPagination(totalPages);
  // sidebar kategori
  const catOrder=['','Toner & Kartuş','Yazıcı & Fotokopi','Ofis ve Kırtasiye','Ambalaj Malzemeleri','Elektronik','Termal & POS Rulo','Temizlik & Hijyen','Defter & Ajanda'];
  const cats=catOrder.map(c=>c?{name:c,val:c}:{name:'Tümü',val:''});
  document.getElementById('catFilters').innerHTML=cats.map(c=>{
    const n=PRODUCTS.filter(p=>!c.val||p.category===c.val).length;
    return `<div class="fil${fCat===c.val?' active':''}" onclick="fCat='${c.val}';fBrand='';searchQuery='';currentPage=1;renderAll()">${c.name}<span class="fil-n">${n}</span></div>`;
  }).join('');
  const list=fCat?PRODUCTS.filter(p=>p.category===fCat):PRODUCTS;
  const brs=[...new Set(list.map(p=>p.brand).filter(Boolean))].sort();
  document.getElementById('brandFilters').innerHTML=[{name:'Tümü',val:''},...brs.map(b=>({name:b,val:b}))].map(b=>{
    const n=list.filter(p=>!b.val||p.brand===b.val).length;
    return `<div class="fil${fBrand===b.val?' active':''}" onclick="fBrand='${b.val}';currentPage=1;renderAll()">${b.name}<span class="fil-n">${n}</span></div>`;
  }).join('');
}

function renderPagination(totalPages) {
  const el = document.getElementById('pagination');
  if (!el) return;
  if (totalPages <= 1) { el.innerHTML = ''; return; }
  let html = '';
  html += `<button class="pg-btn${currentPage===1?' pg-disabled':''}" onclick="if(currentPage>1)goPage(currentPage-1)">‹</button>`;
  let s = Math.max(1, currentPage - 2);
  let e = Math.min(totalPages, s + 4);
  if (e - s < 4) s = Math.max(1, e - 4);
  if (s > 1) {
    html += `<button class="pg-btn" onclick="goPage(1)">1</button>`;
    if (s > 2) html += `<span class="pg-ellipsis">…</span>`;
  }
  for (let i = s; i <= e; i++) {
    html += `<button class="pg-btn${i===currentPage?' pg-active':''}" onclick="goPage(${i})">${i}</button>`;
  }
  if (e < totalPages) {
    if (e < totalPages - 1) html += `<span class="pg-ellipsis">…</span>`;
    html += `<button class="pg-btn" onclick="goPage(${totalPages})">${totalPages}</button>`;
  }
  html += `<button class="pg-btn${currentPage===totalPages?' pg-disabled':''}" onclick="if(currentPage<${totalPages})goPage(currentPage+1)">›</button>`;
  el.innerHTML = html;
}

function goPage(n) {
  currentPage = n;
  renderAll();
  document.getElementById('allPage').scrollIntoView({behavior:'smooth',block:'start'});
}


/* ── MOBİL KATEGORİ MENÜ ── */
function toggleCatMenu(){
  const menu = document.getElementById('catMobileMenu');
  const btn  = document.getElementById('catHamburger');
  const open = menu.classList.toggle('open');
  menu.setAttribute('aria-hidden', !open);
  btn.setAttribute('aria-expanded', open);
  document.body.style.overflow = open ? 'hidden' : '';
}
document.addEventListener('click', function(e){
  const menu = document.getElementById('catMobileMenu');
  if(menu && menu.classList.contains('open') && e.target === menu){
    toggleCatMenu();
  }
});
/* ── PAGE NAVIGATION ── */
function showPage(id) {
  const _cm=document.getElementById("catMobileMenu");if(_cm&&_cm.classList.contains("open"))toggleCatMenu();
  ['homePage','allPage','contactPage','gizlilikPage','erisilebilirlikPage','gonderimPage','sartKosullarPage','iadePage','mesafeliSatisPage'].forEach(p=>{
    const el=document.getElementById(p);
    if(el) el.style.display='none';
  });
  const target=document.getElementById(id);
  if(target) target.style.display='block';
  window.scrollTo(0,0);
}

function showHome() { showPage('homePage'); }

function showAll(el) {
  fCat=''; fBrand=''; searchQuery=''; currentPage=1;
  showPage('allPage');
  renderAll();
  if(el) setActive(el);
}

function showAllCat(cat, el) {
  fCat=cat; fBrand=''; searchQuery=''; currentPage=1;
  showPage('allPage');
  renderAll();
  if(el) setActive(el);
}

function setActive(el) {
  document.querySelectorAll('.cbi').forEach(x=>x.classList.remove('active'));
  if(el) el.classList.add('active');
}

/* ── SEARCH ── */
function doSearch(term) {
  if(term!==undefined){document.getElementById('searchInp').value=term;}
  const q=document.getElementById('searchInp').value.trim();
  const cat=document.getElementById('searchCat').value;
  fCat=cat||''; fBrand=''; searchQuery=q; currentPage=1;
  showPage('allPage');
  renderAll();
}

document.addEventListener('DOMContentLoaded', function() {
  const searchInp = document.getElementById('searchInp');
  if(searchInp) searchInp.addEventListener('keydown',e=>{if(e.key==='Enter')doSearch();});
});

/* ── MODAL ── */
function openModal(idx) {
  const p=PRODUCTS[idx]; if(!p)return; modalProd=p;
  const disc=p.strikePrice&&parseFloat(p.strikePrice)>parseFloat(p.price||0);
  const ms=pImg(p.img,500,500);
  document.getElementById('mImgBox').innerHTML=ms?`<img src="${ms}" data-o="${p.img}" alt="${p.name}" loading="lazy" onerror="this.onerror=null;if(this.src!==this.dataset.o){this.src=this.dataset.o;}else{this.style.display='none';}" style="max-height:250px;max-width:80%;object-fit:contain">`:`<div style="color:#cde0d0"><svg style="width:64px;height:64px" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1"><rect x="3" y="3" width="18" height="18" rx="2"/></svg></div>`;
  document.getElementById('mBrand').textContent=p.brand||'';
  document.getElementById('mName').textContent=p.name;
  document.getElementById('mSku').textContent=p.sku?'SKU: '+p.sku:'';
  const pr=document.getElementById('mPrice'); pr.textContent=fmt(p.price); pr.className='modal-price'+(disc?' disc':'');
  document.getElementById('mOld').textContent=disc?fmt(p.strikePrice):'';
  document.getElementById('mDesc').textContent=p.description||'Ürün detayları için lütfen iletişime geçin.';
  document.getElementById('modalOv').classList.add('open');
  document.body.style.overflow='hidden';
}

function addFromModal(){if(modalProd){addCart(PRODUCTS.indexOf(modalProd),null,true);closeModal();}}
function closeMOv(e){if(e.target===document.getElementById('modalOv'))closeModal();}
function closeModal(){
  document.getElementById('modalOv').classList.remove('open');
  document.body.style.overflow='';
}

/* ── CART ── */
function addCart(idx, btn) {
  const p=PRODUCTS[idx]; if(!p)return;
  const ex=cart.find(c=>c.name===p.name);
  if(ex) ex.qty++; else cart.push({...p,qty:1});
  updateCart();
  showToast(p.name.slice(0,30)+'...');
  if(btn){
    btn.classList.add('added');
    btn.innerHTML='<svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5"><path d="M5 13l4 4L19 7"/></svg>';
    setTimeout(()=>{
      btn.classList.remove('added');
      btn.innerHTML='<svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2.5"><path d="M12 4v16m8-8H4"/></svg>';
    },1200);
  }
}

function updateCart() {
  const tot=cart.reduce((s,c)=>s+parseFloat(c.price||0)*c.qty,0);
  const cnt=cart.reduce((s,c)=>s+c.qty,0);
  document.getElementById('cartBadge').textContent=cnt;
  document.getElementById('cartCnt').textContent=cnt;
  document.getElementById('cartTot').textContent=fmt(tot);
  const el=document.getElementById('cartList');
  if(!cart.length){
    el.innerHTML='<div class="cart-empty-msg"><svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.2"><path d="M3 3h2l.4 2M7 13h10l4-8H5.4M7 13L5.4 5M7 13l-2.293 2.293c-.63.63-.184 1.707.707 1.707H17m0 0a2 2 0 100 4 2 2 0 000-4zm-8 2a2 2 0 11-4 0 2 2 0 014 0z"/></svg><p>Sepetiniz boş</p></div>';
    return;
  }
  el.innerHTML=cart.map((c,i)=>`<div class="citem"><div class="citem-img">${c.img?`<img src="${pImg(c.img,80,80)}" alt="${c.name}" loading="lazy" onerror="this.style.display='none'">`:''}</div><div class="citem-info"><div class="citem-name">${c.name}</div><div class="citem-price">${fmt(parseFloat(c.price||0)*c.qty)}</div><div class="citem-qty"><button class="qbtn" onclick="chQ(${i},-1)" aria-label="Azalt">−</button><span class="qval">${c.qty}</span><button class="qbtn" onclick="chQ(${i},1)" aria-label="Artır">+</button></div></div><button class="citem-del" onclick="rmC(${i})" aria-label="Sil"><svg fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg></button></div>`).join('');
}

function chQ(i,d){cart[i].qty+=d;if(cart[i].qty<=0)cart.splice(i,1);updateCart();}
function rmC(i){cart.splice(i,1);updateCart();}
function toggleCart(){
  document.getElementById('cartDrawer').classList.toggle('open');
  document.getElementById('cartOverlay').classList.toggle('open');
}

/* ── TOAST ── */
let toastT;
function showToast(n){
  document.getElementById('toastTxt').textContent=n+' sepete eklendi';
  const t=document.getElementById('toast');
  t.classList.add('show');
  clearTimeout(toastT);
  toastT=setTimeout(()=>t.classList.remove('show'),2400);
}

/* ── SLIDER ── */
function goSlide(n){
  document.querySelectorAll('.slide').forEach((s,i)=>s.classList.toggle('active',i===n));
  document.querySelectorAll('.sdot').forEach((d,i)=>d.classList.toggle('active',i===n));
  slideIdx=n;
}
function chSlide(d){
  const sl=document.querySelectorAll('.slide');
  goSlide((slideIdx+d+sl.length)%sl.length);
}
setInterval(()=>chSlide(1),5000);

/* ── COUNTDOWN ── */
let secs=8*3600+42*60+17;
setInterval(()=>{
  secs=(secs-1+86400)%86400;
  const h=document.getElementById('cdH');
  const m=document.getElementById('cdM');
  const s=document.getElementById('cdS');
  if(h) h.textContent=String(Math.floor(secs/3600)).padStart(2,'0');
  if(m) m.textContent=String(Math.floor((secs%3600)/60)).padStart(2,'0');
  if(s) s.textContent=String(secs%60).padStart(2,'0');
},1000);

/* ── AUTH ── */
function showAuthModal(){document.getElementById('authOv').style.display='flex';}
function closeAuth(){document.getElementById('authOv').style.display='none';}
function closeAuthIfBg(e){if(e.target===document.getElementById('authOv'))closeAuth();}
function switchAuth(t){
  document.getElementById('authLogin').style.display=t==='login'?'block':'none';
  document.getElementById('authRegister').style.display=t==='register'?'block':'none';
  document.getElementById('tabLogin').classList.toggle('active',t==='login');
  document.getElementById('tabReg').classList.toggle('active',t==='register');
}

/* ── BRANDS SLIDER ── */
(function(){
  let dir=1, paused=false;
  function autoScroll(){
    const r=document.getElementById('brandsRow');
    if(!r||paused)return;
    r.scrollLeft+=dir*0.8;
    if(r.scrollLeft>=r.scrollWidth-r.clientWidth){dir=-1;}
    if(r.scrollLeft<=0){dir=1;}
  }
  setInterval(autoScroll,16);
  window.brandsSlide=function(d){
    const r=document.getElementById('brandsRow');
    r.scrollBy({left:d*220,behavior:'smooth'});
    paused=true; setTimeout(()=>paused=false,2000);
  };
})();

