function sendToWhatsApp() {
  const name = document.getElementById('wa-name').value.trim();
  const tel = document.getElementById('wa-tel').value.trim();
  const adres = document.getElementById('wa-adres').value.trim();
  const odeme = document.getElementById('wa-odeme').value;
  const not = document.getElementById('wa-not').value.trim();

  if (!name) { alert('Lütfen adınızı girin.'); document.getElementById('wa-name').focus(); return; }
  if (!tel) { alert('Lütfen telefon numaranızı girin.'); document.getElementById('wa-tel').focus(); return; }
  if (!adres) { alert('Lütfen teslimat adresinizi girin.'); document.getElementById('wa-adres').focus(); return; }

  const tot = cart.reduce((s, c) => s + parseFloat(c.price || 0) * c.qty, 0);
  const urunler = cart.map(c => `• ${c.name} x${c.qty} — ${fmt(parseFloat(c.price||0)*c.qty)}`).join('\n');

  const msg = `🛒 *YENİ SİPARİŞ – OfiseUygun*

👤 *Ad Soyad:* ${name}
📞 *Telefon:* ${tel}
📍 *Adres:* ${adres}
💳 *Ödeme:* ${odeme}${not ? `\n📝 *Not:* ${not}` : ''}

━━━━━━━━━━━━━━━
📦 *SİPARİŞ DETAYI:*
${urunler}
━━━━━━━━━━━━━━━
💰 *TOPLAM: ${fmt(tot)}*

_ofiseuygun.com üzerinden sipariş verildi._`;

  const phone = '905398136317';
  const url = `https://wa.me/${phone}?text=${encodeURIComponent(msg)}`;
  window.open(url, '_blank');
  closeWAModal();
  cart = [];
  updateCart();
  toggleCart();
  showToast('Siparişiniz WhatsApp\'a yönlendirildi! 🎉');
}

function closeWAModal() {
  const m = document.getElementById('waModalOv');
  if (m) m.remove();
}

/* ── DROPDOWN POZİSYON (mobil taşmasın) ── */
document.querySelectorAll('.cbi').forEach(cbi => {
  cbi.addEventListener('mouseenter', () => positionDropdown(cbi));
  cbi.addEventListener('focusin', () => positionDropdown(cbi));
});
function positionDropdown(cbi) {
  const dd = cbi.querySelector('.dropdown');
  if (!dd) return;
  const rect = cbi.getBoundingClientRect();
  dd.style.top = (rect.bottom) + 'px';
  const ddW = dd.offsetWidth || 220;
  let left = rect.left;
  if (left + ddW > window.innerWidth - 12) left = window.innerWidth - ddW - 12;
  if (left < 12) left = 12;
  dd.style.left = left + 'px';
}

/* ── ÜRÜN SLIDER KAYDIRMA ── */
function scrollRow(id, dir) {
  const el = document.getElementById(id);
  if (!el) return;
  const card = el.querySelector('.pcard');
  const cardW = card ? card.offsetWidth + 12 : 220;
  el.scrollBy({ left: dir * cardW * 2, behavior: 'smooth' });
}

/* ── MOBİL KATEGORİ BAR SCROLL ── */
(function(){
  const inner = document.querySelector('.cat-bar-inner');
  if (!inner) return;
  let isDown = false, startX, scrollLeft;
  inner.addEventListener('mousedown', e => {
    isDown = true; startX = e.pageX - inner.offsetLeft; scrollLeft = inner.scrollLeft;
  });
  inner.addEventListener('mouseleave', () => isDown = false);
  inner.addEventListener('mouseup', () => isDown = false);
  inner.addEventListener('mousemove', e => {
    if (!isDown) return;
    e.preventDefault();
    inner.scrollLeft = scrollLeft - (e.pageX - inner.offsetLeft - startX);
  });
})();

